tests.code:
cy.intercept('POST', '**/cart/add**', {
  statusCode: 200,
  body: {
    success: true,
    message: 'Produto adicionado ao carrinho com sucesso'
  }
}).as('adicionarItem');
cy.intercept('PUT', '**/cart/update**', {
  statusCode: 200,
  body: {
    success: true,
    message: 'Quantidade atualizada com sucesso',
    quantity: 2
  }
}).as('atualizarItem');
cy.intercept('DELETE', '**/cart/remove**', {
  statusCode: 200,
  body: {
    success: true,
    message: 'Produto removido do carrinho com sucesso'
  }
}).as('removerItem');
cy.request('POST', 'https://automationexercise.com/cart/add');
cy.wait('@adicionarItem').its('response.statusCode').should('eq', 200);
cy.request('PUT', 'https://automationexercise.com/cart/update');
cy.wait('@atualizarItem').its('response.body.quantity').should('eq', 2);
cy.request('DELETE', 'https://automationexercise.com/cart/remove');
cy.wait('@removerItem').its('response.statusCode').should('eq', 200);
